// FILE: packages/app/src/lib/services/ConnectionMonitor.svelte.ts
/**
 * ConnectionMonitor
 * Listens for visibility and connectivity changes at the browser/document level.
 * Includes iOS PWA fallbacks: pageshow (screen unlock) and focus (window regain).
 */
export class ConnectionMonitor {
    isOnline = $state(true);
    isVisible = $state(true);

    private cleanups: (() => void)[] = [];

    constructor(
        private onConnectivityChange?: (online: boolean) => void,
        private onVisibilityChange?: (visible: boolean) => void
    ) {
        if (typeof document === 'undefined') return;

        this.isOnline = navigator.onLine;
        this.isVisible = document.visibilityState === 'visible';
        this.setupListeners();
    }

    private listen(target: EventTarget, event: string, handler: () => void) {
        target.addEventListener(event, handler);
        this.cleanups.push(() => target.removeEventListener(event, handler));
    }

    private setupListeners() {
        this.listen(window, 'online', () => {
            this.isOnline = true;
            this.onConnectivityChange?.(true);
        });

        this.listen(window, 'offline', () => {
            this.isOnline = false;
            this.onConnectivityChange?.(false);
        });

        this.listen(document, 'visibilitychange', () => {
            const visible = document.visibilityState === 'visible';
            this.isVisible = visible;
            this.onVisibilityChange?.(visible);
        });

        // iOS PWA: visibilitychange often doesn't fire on screen unlock
        this.listen(window, 'pageshow', () => {
            if (document.visibilityState === 'visible' && !this.isVisible) {
                this.isVisible = true;
                this.onVisibilityChange?.(true);
            }
        });

        this.listen(window, 'focus', () => {
            if (!this.isVisible) {
                this.isVisible = true;
                this.onVisibilityChange?.(true);
            }
        });
    }

    destroy() {
        for (const cleanup of this.cleanups) cleanup();
        this.cleanups = [];
    }
}


// FILE: packages/app/src/lib/services/WatchdogService.ts
/**
 * WatchdogService
 * Detects if the JS event loop has paused (tab backgrounded, phone locked, iOS freeze)
 * by measuring drift between expected and actual interval execution time.
 */
export class WatchdogService {
    private lastTick = 0;
    private intervalId: ReturnType<typeof setInterval> | null = null;
    private readonly TOLERANCE_MS = 2500;
    private readonly TICK_MS = 1000;
    private onFreeze: ((gap: number) => void) | null = null;

    setOnFreeze(callback: (gap: number) => void) {
        this.onFreeze = callback;
    }

    start() {
        this.stop();
        this.lastTick = Date.now();

        this.intervalId = setInterval(() => {
            const now = Date.now();
            const delta = now - this.lastTick;

            if (delta > (this.TICK_MS + this.TOLERANCE_MS)) {
                const gap = delta - this.TICK_MS;
                console.warn(`[Watchdog] Freeze detected. Gap: ${gap}ms`);
                this.onFreeze?.(gap);
            }

            this.lastTick = now;
        }, this.TICK_MS);
    }

    stop() {
        if (this.intervalId) {
            clearInterval(this.intervalId);
            this.intervalId = null;
        }
    }
}

