        let ticking = false;
        function onScroll() {
            if (ticking) return;
            ticking = true;
            requestAnimationFrame(() => {
                ticking = false;
                const centerY = window.innerHeight / 2;
                const centerX = window.innerWidth / 2;
                const el = document.elementFromPoint(centerX, centerY);
