<script lang="ts">
    import { onMount } from 'svelte';
    import { appState } from '$lib/state/index.svelte.js';
    import { sentinel } from '$lib/actions/sentinel.js';
    import { SENTINEL_ROOT_MARGIN } from '$lib/constants.js';
    import SearchBar from '$lib/components/SearchBar.svelte';
    import VideoList from '$lib/components/VideoList.svelte';

    const results = $derived(appState.searchState.results);
    const total = $derived(results.length);
    const query = $derived(appState.searchState.currentQuery);
    const isLoading = $derived(appState.searchState.isLoading);
    const hasMore = $derived(appState.searchState.hasMore);

    // Request video details for visible results
    $effect(() => {
        if (results.length > 0) {
            const urls = results.map(v => v.pageUrl);
            appState.videoDetails.requestDetails(urls);
        }
    });

    // Track which video card is visible at viewport center
    onMount(() => {
        const listEl = document.getElementById('view-list');
        if (!listEl) return;

        let ticking = false;
        function onScroll() {
            if (ticking) return;
            ticking = true;
            requestAnimationFrame(() => {
                ticking = false;
                const centerY = window.innerHeight / 2;
                const centerX = window.innerWidth / 2;
                const el = document.elementFromPoint(centerX, centerY);
                if (!el) return;
                const card = el.closest('[data-video-id]');
                if (card) {
                    const id = card.getAttribute('data-video-id');
                    if (id) appState.trackVisibleVideo(id);
                }
            });
        }

        listEl.addEventListener('scroll', onScroll, { passive: true });
        return () => listEl.removeEventListener('scroll', onScroll);
    });
</script>

