import { chromium } from 'playwright';
import { USER_AGENT } from '../config';

interface CachedCookies {
  cookieHeader: string;
  obtainedAt: number;
}

const cookieCache = new Map<string, CachedCookies>();
const solvingDomains = new Set<string>();

export function isCloudflareBlock(status: number, serverHeader: string | null): boolean {
  return (status === 403 || status === 503) && (serverHeader ?? '').toLowerCase().includes('cloudflare');
}

export function getCachedCookies(domain: string): string | null {
  const cached = cookieCache.get(domain);
  if (!cached) return null;
  if (Date.now() - cached.obtainedAt > 30 * 60 * 1000) {
    cookieCache.delete(domain);
    return null;
  }
  return cached.cookieHeader;
}

export function clearCachedCookies(domain: string): void {
  cookieCache.delete(domain);
}

export function isSolving(domain: string): boolean {
  return solvingDomains.has(domain);
}

export async function solveCloudflareCookies(url: string): Promise<string> {
  const domain = new URL(url).hostname;

  if (solvingDomains.has(domain)) {
    throw new Error(`Already solving for ${domain}`);
  }

  solvingDomains.add(domain);
  console.log(`[cloudflare] Starting solve for ${domain}`);

  let browser;
  try {
    browser = await chromium.launch({
      headless: false,
      args: [
        '--no-sandbox',
        '--disable-setuid-sandbox',
        '--disable-gpu',
        '--disable-gpu-compositing',
        '--window-size=1920,1080',
      ],
    });

    const context = await browser.newContext({
      userAgent: USER_AGENT,
      viewport: { width: 1920, height: 1080 },
    });

    const page = await context.newPage();
    await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 30_000 });

    let cookieHeader: string | null = null;
    const deadline = Date.now() + 30_000;

    while (Date.now() < deadline) {
      const cookies = await context.cookies();
      const cfCookie = cookies.find(c => c.name === 'cf_clearance');
      if (cfCookie) {
        const domainCookies = cookies.filter(c =>
          domain.endsWith(c.domain.replace(/^\./, ''))
        );
        cookieHeader = domainCookies.map(c => `${c.name}=${c.value}`).join('; ');
        break;
      }
      await page.waitForTimeout(1000);
    }

    if (!cookieHeader) {
      throw new Error(`Cloudflare solve timed out for ${domain}`);
    }

    console.log(`[cloudflare] Solved for ${domain}`);
    cookieCache.set(domain, { cookieHeader, obtainedAt: Date.now() });
    return cookieHeader;
  } finally {
    solvingDomains.delete(domain);
    if (browser) {
      await browser.close().catch(() => {});
    }
  }
}


// FILE: packages/server/src/utils/proxyFetch.ts
import { PROXY_TIMEOUT } from '../config';
import { isCloudflareBlock, getCachedCookies, clearCachedCookies, isSolving, solveCloudflareCookies } from './cloudflare';

export class UpstreamError extends Error {
  status: number;
  statusText: string;
  url: string;

  constructor(status: number, statusText: string, url: string) {
    super(`Upstream ${status} ${statusText} from ${url}`);
    this.name = 'UpstreamError';
    this.status = status;
    this.statusText = statusText;
    this.url = url;
  }
}

export class CloudflareError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'CloudflareError';
  }
}

export interface ProxyFetchOptions extends RequestInit {
  cloudflareProtected?: boolean;
}

export async function proxyFetch(
  url: string,
  init?: ProxyFetchOptions,
  timeout = PROXY_TIMEOUT,
) {
  const { cloudflareProtected, ...fetchInit } = init ?? {};
  const domain = new URL(url).hostname;

  if (cloudflareProtected) {
    const cachedCookies = getCachedCookies(domain);
    if (cachedCookies) {
      const headers = new Headers(fetchInit.headers);
      headers.set('Cookie', cachedCookies);
      fetchInit.headers = Object.fromEntries(headers.entries());
    }
  }

  const start = Date.now();
  const r = await fetch(url, {
    ...fetchInit,
    signal: fetchInit.signal ?? AbortSignal.timeout(timeout),
  });
  const duration = Date.now() - start;
  console.log(`[proxy] ${new URL(url).pathname} ${r.status} ${duration}ms`);

  if (!r.ok && cloudflareProtected && isCloudflareBlock(r.status, r.headers.get('server'))) {
    if (getCachedCookies(domain)) {
      clearCachedCookies(domain);
    }

    if (isSolving(domain)) {
      throw new CloudflareError(`Cloudflare solve in progress for ${domain}`);
    }

    solveCloudflareCookies(url).catch(err => {
      console.error(`[cloudflare] Solve failed for ${domain}:`, err.message);
    });

    throw new CloudflareError(`Cloudflare block detected for ${domain}, solving started`);
  }

  if (!r.ok) {
    throw new UpstreamError(r.status, r.statusText, url);
  }
  return r;
}


