}

// ─── User ────────────────────────────────────────────────────

export interface User {
	id: string;
	name: string;
	email: string;
	iban: string;
}

// ─── Bank API Methods ────────────────────────────────────────

export interface BankAPI {
	// Accounts
	getAccount(accountId: string): BankAccount | null;
