import type { ViewMode } from '../types.js';
import { getJson, setJson, remove } from '../services/storage.js';

const SESSION_KEY = 'session';

export interface SessionSnapshot {
    viewMode: ViewMode;
    viewStack: ViewMode[];
    activeGalleryId?: number;
    searchQuery?: string;
