import { spawn, ChildProcess, execSync } from 'child_process';
import fs from 'fs';
import path from 'path';
import { hitomi } from 'gallery-sources';
import { CONFIG } from './config.js';
import { socketService } from './socket.service.js';
import { stripAnsi, getUniqueItems } from './utils.js';

const SOURCE_DIR = path.join(CONFIG.WORKING_DIR, hitomi.gallerySubdir);
const QUEUE_FILE = path.join(SOURCE_DIR, '.queue-backup.json');

// Remove stale markers from previous runs (e.g. power failure, crash)
try {
    for (const f of fs.readdirSync(SOURCE_DIR)) {
        if (f.startsWith('.downloading-')) fs.unlinkSync(path.join(SOURCE_DIR, f));
    }
} catch (_) {}

function saveQueue(currentUrl: string | null, queue: string[], paused: boolean = false) {
    const data = { currentUrl, queue, paused, savedAt: new Date().toISOString() };
    try { fs.writeFileSync(QUEUE_FILE, JSON.stringify(data)); } catch (_) {}
}

function loadQueue(): { currentUrl: string | null; queue: string[]; paused: boolean } | null {
    try {
        const raw = JSON.parse(fs.readFileSync(QUEUE_FILE, 'utf-8'));
        const urls: string[] = [];
        if (raw.currentUrl) urls.push(raw.currentUrl);
        if (Array.isArray(raw.queue)) urls.push(...raw.queue);
        if (urls.length === 0) return null;
        return { currentUrl: null, queue: urls, paused: !!raw.paused };
    } catch (_) { return null; }
}

function clearQueueFile() {
    try { fs.unlinkSync(QUEUE_FILE); } catch (_) {}
}

function extractGalleryId(url: string): string | null {
    return hitomi.download.parseIdFromUrl(url);
}

function markerPath(galleryId: string): string {
    return path.join(SOURCE_DIR, hitomi.downloadingMarker(galleryId));
}

function createMarker(galleryId: string) {
    try { fs.writeFileSync(markerPath(galleryId), ''); } catch (_) {}
}

function removeMarker(galleryId: string) {
    try { fs.unlinkSync(markerPath(galleryId)); } catch (_) {}
}

function deletePartialGallery(galleryId: string) {
    // Delete gallery directory from disk
    const dirPath = path.join(SOURCE_DIR, galleryId);
    try {
        fs.rmSync(dirPath, { recursive: true, force: true });
        console.log(`Deleted partial gallery dir: ${galleryId}`);
    } catch (_) {}
    // Remove archive entries
    const archivePath = hitomi.download.archivePath(CONFIG.WORKING_DIR);
    try {
        execSync(`sqlite3 "${archivePath}" "DELETE FROM archive WHERE entry LIKE 'hitomi${galleryId}_%'"`, { stdio: 'pipe' });
        console.log(`Cleaned archive entries for gallery ${galleryId}`);
    } catch (_) {}
    // Remove marker
    removeMarker(galleryId);
}

export type DownloadValidator = (galleryId: string) => { valid: boolean; reason?: string };

export interface QueueStatus {
    running: boolean;
    stopped: boolean;
    paused: boolean;
    currentUrl: string;
    queue: string[];
}

class QueueManager {
    private downloadQueue: string[] = [];
    private currentChild: ChildProcess | null = null;
    private currentUrl: string | null = null;
    private currentGalleryId: string | null = null;
    private isInterrupted: boolean = false;
    private stopSignal: boolean = false;
    private pauseSignal: boolean = false;
    private validator: DownloadValidator | null = null;
    private onComplete: ((galleryId: string) => void) | null = null;

    public setValidator(fn: DownloadValidator) {
        this.validator = fn;
    }

    public setOnComplete(fn: (galleryId: string) => void) {
        this.onComplete = fn;
    }

    public getStatus(): QueueStatus {
        return {
            running: !!this.currentChild,
            stopped: this.stopSignal,
            paused: this.pauseSignal,
            currentUrl: this.currentUrl || '',
            queue: this.downloadQueue
        };
    }

    private emitState() {
        socketService.emitStatus(this.getStatus());
        this.persist();
    }

    private persist() {
        if (this.downloadQueue.length === 0 && !this.currentUrl) {
            clearQueueFile();
        } else {
            saveQueue(this.currentUrl, this.downloadQueue, this.pauseSignal);
        }
    }

    public processQueue() {
        if (this.currentChild || this.stopSignal || this.pauseSignal) return;

        if (this.downloadQueue.length === 0) {
            this.currentUrl = null;
            this.emitState();
            socketService.emitLog('Queue finished. Waiting for commands...\n');
            return;
        }

        this.currentUrl = this.downloadQueue.shift() || null;
        if (!this.currentUrl) return;

        this.currentGalleryId = extractGalleryId(this.currentUrl);
        if (this.currentGalleryId) {
            createMarker(this.currentGalleryId);
        }

        this.emitState();
        socketService.emitLog(`\n--- STARTING: ${this.currentUrl} ---\n`);

        this.currentChild = spawn(CONFIG.PYTHON_PATH, [CONFIG.GALLERY_DL_SCRIPT, ...CONFIG.BASE_ARGS, this.currentUrl], {
            cwd: CONFIG.WORKING_DIR
        });

        this.currentChild.on('error', (err) => {
            socketService.emitLog(`\n--- SPAWN ERROR: ${err.message} ---\n`);
            if (this.currentGalleryId) removeMarker(this.currentGalleryId);
            this.currentChild = null;
            this.currentGalleryId = null;

            if (!this.isInterrupted && !this.stopSignal) {
                this.processQueue();
            }
        });

        this.currentChild.stdout?.on('data', (data) => {
            socketService.emitLog(stripAnsi(data.toString()));
        });

        this.currentChild.stderr?.on('data', (data) => {
            socketService.emitLog(`[ERR] ${stripAnsi(data.toString())}`);
        });

        this.currentChild.on('close', (code) => {
            socketService.emitLog(`\n--- FINISHED (Code ${code}) ---\n`);
            const completedGalleryId = this.currentGalleryId;

            if (!this.isInterrupted && !this.stopSignal) {
                let rejected = false;

                // Post-download validation (only on clean exit)
                if (code === 0 && completedGalleryId && this.validator) {
                    const check = this.validator(completedGalleryId);
                    if (!check.valid) {
                        console.log(`[validate] rejected ${completedGalleryId}: ${check.reason}`);
                        socketService.emitLog(`[REJECTED] ${completedGalleryId}: ${check.reason}\n`);
                        deletePartialGallery(completedGalleryId);
                        rejected = true;
                    }
                }

                if (!rejected && completedGalleryId) {
                    removeMarker(completedGalleryId);
                    this.onComplete?.(completedGalleryId);
                }
            }

            this.currentChild = null;
            this.currentGalleryId = null;

            if (!this.isInterrupted && !this.stopSignal) {
                this.processQueue();
            }
        });
    }

    public updateQueue(rawUrls: string[]) {
        this.downloadQueue = getUniqueItems(rawUrls, [], this.currentUrl);
        this.stopSignal = false;
        this.emitState();
        this.processQueue();
    }

    public injectImmediate(rawUrls: string[]) {
        if (rawUrls.length === 0) return;

        console.log(`IMMEDIATE REQUEST: ${rawUrls.length} items.`);
        this.stopSignal = false;

        const newActive = rawUrls[0];
        const newFrontOfQueue = getUniqueItems(rawUrls.slice(1), [], this.currentUrl);

        if (this.currentChild) {
            this.isInterrupted = true;
            this.currentChild.kill('SIGINT');

            const oldUrl = this.currentUrl;
            const combined = [...newFrontOfQueue];
            if (oldUrl) combined.push(oldUrl);
            combined.push(...this.downloadQueue);

            this.downloadQueue = getUniqueItems(combined, [], newActive);
            this.downloadQueue.unshift(newActive);

            setTimeout(() => {
                this.isInterrupted = false;
                this.processQueue();
            }, 1000);
        } else {
            this.downloadQueue = getUniqueItems([...newFrontOfQueue, ...this.downloadQueue], [], newActive);
            this.downloadQueue.unshift(newActive);
            this.processQueue();
        }
    }

    public pause() {
        this.pauseSignal = true;
        this.emitState();
        socketService.emitLog('\n--- PAUSED (will finish current download) ---\n');
    }

    public resume() {
        this.pauseSignal = false;
        this.emitState();
        socketService.emitLog('\n--- RESUMED ---\n');
        this.processQueue();
    }

    public cancel() {
        this.stopSignal = true;
        const partialId = this.currentGalleryId;
        if (this.currentChild) {
            socketService.emitLog(`\n--- CANCELLING... ---\n`);
            this.currentChild.kill('SIGINT');
        } else {
            socketService.emitLog(`\n--- QUEUE STOPPED ---\n`);
        }
        // Clean up partial download
        if (partialId) {
            deletePartialGallery(partialId);
            socketService.emitLog(`Deleted partial gallery ${partialId}\n`);
        }
        this.downloadQueue = [];
        this.currentUrl = null;
        this.currentGalleryId = null;
        this.pauseSignal = false;
        this.emitState();
    }

    /**
     * Append gallery IDs to the queue without replacing existing items.
     * Converts IDs to hitomi URLs. Deduplicates against current queue + active download.
     */
    public appendQueue(galleryIds: number[]) {
        const existingUrls = new Set(this.downloadQueue);
        if (this.currentUrl) existingUrls.add(this.currentUrl);

        let added = 0;
        for (const id of galleryIds) {
            const url = `https://hitomi.la/galleries/${id}.html`;
            if (!existingUrls.has(url)) {
                this.downloadQueue.push(url);
                existingUrls.add(url);
                added++;
            }
        }

        if (added > 0) {
            this.stopSignal = false;
            this.emitState();
            this.processQueue();
        }

        return added;
    }

    public restore() {
        const saved = loadQueue();
        if (!saved || saved.queue.length === 0) return;
        console.log(`Restoring ${saved.queue.length} queued items from backup...`);
        this.downloadQueue = saved.queue;
        this.stopSignal = false;
        this.pauseSignal = saved.paused;
        this.emitState();
        if (saved.paused) {
            console.log('Queue was paused — waiting for resume.');
        } else {
            this.processQueue();
        }
    }
}

export const queueManager = new QueueManager();


// FILE: gallery-server/downloader/src/remove.ts
import fs from 'fs';
import path from 'path';
import https from 'https';
import { execSync } from 'child_process';
import Database from 'better-sqlite3';
import { loadManifest } from './manifest.js';
import { resolveManifest, resolveEntryWithFilters } from './manifest-resolver.js';
import { CONFIG } from './config.js';

const INDEX_DB_PATH = path.join(CONFIG.WORKING_DIR, 'gallery-dl', 'gallery-index.db');
const STREAMER_PORT = 11556;

export interface RemoveStatus {
    phase: 'idle' | 'resolving-removed' | 'resolving-remaining' | 'diffing' | 'deleting' | 'committing' | 'done' | 'error';
    removedLine: string;
    removedIdCount: number;
    resolvedCount: number;
    resolvedTotal: number;
    wantedCount: number;
    localCount: number;
    orphanCount: number;
    deletedCount: number;
    skippedCount: number;
    error: string | null;
}

let currentRemove: RemoveStatus = {
    phase: 'idle',
    removedLine: '',
    removedIdCount: 0,
    resolvedCount: 0,
    resolvedTotal: 0,
    wantedCount: 0,
    localCount: 0,
    orphanCount: 0,
    deletedCount: 0,
    skippedCount: 0,
    error: null,
};

let removeRunning = false;

export function getRemoveStatus(): RemoveStatus {
    return { ...currentRemove };
}

function log(msg: string) {
    console.log(`[remove] ${msg}`);
}

function logError(msg: string) {
    console.error(`[remove] ${msg}`);
}

function removeLineFromFile(filePath: string, line: string): string | null {
    const content = fs.readFileSync(filePath, 'utf-8');
    const lines = content.split('\n');
    const target = line.trim();
    const idx = lines.findIndex(l => l.trim() === target);
    if (idx === -1) return null;
    lines.splice(idx, 1);
    fs.writeFileSync(filePath, lines.join('\n'));
    return content;
}

function restoreFile(filePath: string, originalContent: string) {
    fs.writeFileSync(filePath, originalContent);
}

function getLocalIds(): Set<number> {
    const ids = new Set<number>();
    if (fs.existsSync(INDEX_DB_PATH)) {
        const db = new Database(INDEX_DB_PATH, { readonly: true });
        db.pragma('journal_mode = WAL');
        const rows = db.prepare('SELECT gallery_id FROM galleries').all() as { gallery_id: number }[];
        for (const row of rows) ids.add(row.gallery_id);
        db.close();
    }
    return ids;
}

function requestDeletion(ids: number[]): Promise<{ deleted: number[]; skipped: { id: number; reason: string }[] }> {
    return new Promise((resolve, reject) => {
        const body = JSON.stringify({ ids });
        const req = https.request(
            {
                hostname: 'localhost',
                port: STREAMER_PORT,
                path: '/api/delete',
                method: 'POST',
                rejectUnauthorized: false,
                headers: {
                    'Content-Type': 'application/json',
                    'Content-Length': Buffer.byteLength(body),
                },
            },
            (res) => {
                let data = '';
                res.on('data', (chunk) => (data += chunk));
                res.on('end', () => {
                    try {
                        resolve(JSON.parse(data));
                    } catch {
                        reject(new Error(`Bad response from streamer: ${data}`));
                    }
                });
            },
        );
        req.on('error', (err) => reject(new Error(`Streamer connection failed: ${err.message}`)));
        req.write(body);
        req.end();
    });
}

export function gitCommit(filePath: string, message: string): boolean {
    const repoRoot = path.resolve(filePath, '..', '..');
    try {
        execSync(`git add ${JSON.stringify(filePath)}`, { cwd: repoRoot, stdio: 'pipe' });
        execSync(`git commit -m ${JSON.stringify(message)}`, { cwd: repoRoot, stdio: 'pipe' });
        return true;
    } catch {
        return false;
    }
}

export async function runRemove(
    file: 'artists' | 'queries',
    line: string,
    filtersPath: string,
    artistsPath: string,
    queriesPath: string,
): Promise<RemoveStatus> {
    if (removeRunning) return currentRemove;

    removeRunning = true;

    const filePath = file === 'artists' ? artistsPath : queriesPath;
    const t0 = Date.now();

    currentRemove = {
        phase: 'resolving-removed',
        removedLine: line,
        removedIdCount: 0,
        resolvedCount: 0,
        resolvedTotal: 0,
        wantedCount: 0,
        localCount: 0,
        orphanCount: 0,
        deletedCount: 0,
        skippedCount: 0,
        error: null,
    };

    let originalContent: string | null = null;

    try {
        log(`start ${line} from ${file}.txt`);

        // Resolve the removed entry's filtered IDs (same policy as sync)
        const manifestBefore = loadManifest(filtersPath, artistsPath, queriesPath);
        const removed = await resolveEntryWithFilters(manifestBefore, file, line);
        currentRemove.removedIdCount = removed.ids.size;

        // Remove line from file (save original for rollback)
        originalContent = removeLineFromFile(filePath, line);
        if (originalContent === null) {
            currentRemove.phase = 'error';
            currentRemove.error = `line not found in ${file}.txt: ${line}`;
            logError(currentRemove.error);
            return currentRemove;
        }

        // Resolve remaining manifest (with filters applied)
        currentRemove.phase = 'resolving-remaining';
        const remaining = await resolveManifest(filtersPath, artistsPath, queriesPath, {
            onArtistResolved: (resolved, total) => {
                currentRemove.resolvedTotal = total;
                currentRemove.resolvedCount = resolved;
            },
            onQueryResolved: (_resolved, _total, _queryIds, _totalIds) => {
                currentRemove.resolvedCount++;
            },
        });
        currentRemove.wantedCount = remaining.wantedIds.size;
        currentRemove.resolvedTotal = remaining.artistCount + remaining.queryCount;

        if (remaining.errors.length > 0) {
            restoreFile(filePath, originalContent);
            originalContent = null;
            currentRemove.phase = 'error';
            currentRemove.error = `${remaining.errors.length} resolution failures, aborting`;
            for (const e of remaining.errors) logError(e);
            logError('incomplete wanted set, rolled back file change');
            return currentRemove;
        }

        // Compute orphans: (removed IDs) ∩ (local) - (still wanted)
        currentRemove.phase = 'diffing';
        const localIds = getLocalIds();
        currentRemove.localCount = localIds.size;

        const orphans: number[] = [];
        for (const id of removed.ids) {
            if (localIds.has(id) && !remaining.wantedIds.has(id)) {
                orphans.push(id);
            }
        }
        currentRemove.orphanCount = orphans.length;

        if (orphans.length > 0) {
            currentRemove.phase = 'deleting';
            log(`deleting ${orphans.length} orphans`);
            const result = await requestDeletion(orphans);
            currentRemove.deletedCount = result.deleted.length;
            currentRemove.skippedCount = result.skipped.length;
            for (const s of result.skipped) {
                logError(`skip ${s.id}: ${s.reason}`);
            }
        }

        currentRemove.phase = 'committing';
        const commitMsg = `remove ${line} from ${file}.txt`;
        if (!gitCommit(filePath, commitMsg)) {
            logError(`git commit failed: ${commitMsg}`);
        }

        currentRemove.phase = 'done';
        log(`done ${currentRemove.deletedCount} deleted, ${currentRemove.skippedCount} skipped, ${((Date.now() - t0) / 1000).toFixed(1)}s`);
        return currentRemove;
    } catch (e) {
        currentRemove.phase = 'error';
        currentRemove.error = String(e);
        logError(String(e));

        if (originalContent !== null) {
            restoreFile(filePath, originalContent);
            log('rolled back file change');
        }

        return currentRemove;
    } finally {
        removeRunning = false;
    }
}


// FILE: gallery-server/downloader/src/resolver.ts
/**
 * Resolver: fetches gallery IDs from hitomi's nozomi API.
 *
 * Pure function: (tags) → Set<number>. No side effects, no DB access.
 * Only reads from hitomi's CDN.
 *
 * Nozomi format: array of big-endian 32-bit unsigned integers.
 * URL pattern: https://ltn.{DOMAIN}/n/{ns}/{tag}-{language}.nozomi
 */

import https from 'https';
import { URL } from 'url';

const DOMAIN = 'gold-usergeneratedcontent.net';
const ORIGIN = 'https://hitomi.la';

function decodeNozomi(buffer: Buffer): Set<number> {
    const ids = new Set<number>();
    for (let i = 0; i + 3 < buffer.length; i += 4) {
        ids.add(buffer.readUInt32BE(i));
    }
    return ids;
}

function buildNozomiUrl(query: string, language: string): string {
    const colonIdx = query.indexOf(':');
    if (colonIdx === -1) throw new Error(`Invalid query token: ${query}`);

    const ns = query.slice(0, colonIdx);
    const tag = query.slice(colonIdx + 1).replace(/_/g, ' ');

    if (ns === 'language') {
        return `https://ltn.${DOMAIN}/n/${encodeURIComponent('index')}-${encodeURIComponent(tag)}.nozomi`;
    }

    // female: and male: tags live under tag/ with the full prefix
    if (ns === 'female' || ns === 'male') {
        const fullTag = `${ns}:${tag}`;
        return `https://ltn.${DOMAIN}/n/tag/${encodeURIComponent(fullTag)}-${encodeURIComponent(language)}.nozomi`;
    }

    // tag: namespace also lives under tag/
    if (ns === 'tag') {
        return `https://ltn.${DOMAIN}/n/tag/${encodeURIComponent(tag)}-${encodeURIComponent(language)}.nozomi`;
    }

    // artist, group, series, character, type
    return `https://ltn.${DOMAIN}/n/${ns}/${encodeURIComponent(tag)}-${encodeURIComponent(language)}.nozomi`;
}

function fetchNozomi(url: string): Promise<Set<number>> {
    return new Promise((resolve, reject) => {
        const parsed = new URL(url);
        const req = https.request({
            hostname: parsed.hostname,
            path: parsed.pathname,
            method: 'GET',
            headers: {
                'Origin': ORIGIN,
                'Referer': ORIGIN + '/',
            },
        }, (res) => {
            if (res.statusCode === 404) {
                // Tag doesn't exist on hitomi — empty set, not an error
                resolve(new Set());
                res.resume();
                return;
            }
            if (res.statusCode !== 200) {
                res.resume();
                reject(new Error(`HTTP ${res.statusCode} for ${url}`));
                return;
            }
            const chunks: Buffer[] = [];
            res.on('data', (chunk) => chunks.push(chunk));
            res.on('end', () => resolve(decodeNozomi(Buffer.concat(chunks))));
            res.on('error', reject);
        });
        req.on('error', reject);
        req.setTimeout(30_000, () => {
            req.destroy(new Error(`Timeout fetching ${url}`));
        });
        req.end();
    });
}

/** Small delay between requests to avoid hammering hitomi */
function delay(ms: number): Promise<void> {
    return new Promise(r => setTimeout(r, ms));
}

export interface ResolveResult {
    ids: Set<number>;
    errors: string[];
}

/**
 * Fetch the ID set for a single tag token (e.g. "tag:anthology") in a language.
 */
export async function resolveTag(token: string, language: string): Promise<ResolveResult> {
    const url = buildNozomiUrl(token, language);
    const errors: string[] = [];
    try {
        const ids = await fetchNozomi(url);
        return { ids, errors };
    } catch (e) {
        errors.push(`${token}: ${e instanceof Error ? e.message : String(e)}`);
        return { ids: new Set(), errors };
    }
}

/**
 * Resolve a single artist/group entry from artists.txt.
 * Returns all gallery IDs for that entry on hitomi.
 */
export async function resolveArtistEntry(
    namespace: string,
    value: string,
    language: string,
): Promise<ResolveResult> {
    const query = `${namespace}:${value}`;
    const url = buildNozomiUrl(query, language);
    const errors: string[] = [];
    try {
        const ids = await fetchNozomi(url);
        return { ids, errors };
    } catch (e) {
        errors.push(`${query}: ${e instanceof Error ? e.message : String(e)}`);
        return { ids: new Set(), errors };
    }
}

/**
 * Resolve a full search query (like queries.txt lines).
 * Positive tokens are intersected, negative tokens are subtracted.
 */
export async function resolveQuery(queryLine: string): Promise<ResolveResult> {
    const tokens = queryLine.trim().split(/\s+/).filter(t => t.length > 0);
    const positive: string[] = [];
    const negative: string[] = [];

    for (const t of tokens) {
        if (t.startsWith('-')) {
            negative.push(t.slice(1));
        } else {
            positive.push(t);
        }
    }

    // Determine language from positive tokens (default: "all")
    let language = 'all';
    const nonLangPositive: string[] = [];
    for (const t of positive) {
        if (t.startsWith('language:')) {
            language = t.slice('language:'.length).replace(/_/g, ' ');
        } else {
            nonLangPositive.push(t);
        }
    }

    const errors: string[] = [];

    // Start with the language set if specified, otherwise all
    let result: Set<number> | null = null;

    if (language !== 'all') {
        const url = buildNozomiUrl(`language:${language}`, language);
        try {
            result = await fetchNozomi(url);
        } catch (e) {
            errors.push(`language:${language}: ${e instanceof Error ? e.message : String(e)}`);
            return { ids: new Set(), errors };
        }
        await delay(100);
    }

    // Intersect positive (non-language) tokens
    for (const tag of nonLangPositive) {
        const url = buildNozomiUrl(tag, language);
        try {
            const ids = await fetchNozomi(url);
            if (result === null) {
                result = ids;
            } else {
                // Intersect in place
                for (const id of result) {
                    if (!ids.has(id)) result.delete(id);
                }
            }
        } catch (e) {
            errors.push(`${tag}: ${e instanceof Error ? e.message : String(e)}`);
        }
        await delay(100);
    }

    if (result === null) {
        return { ids: new Set(), errors };
    }

    // Subtract negative tokens
    for (const tag of negative) {
        const url = buildNozomiUrl(tag, language);
        try {
            const ids = await fetchNozomi(url);
            for (const id of ids) {
                result.delete(id);
            }
        } catch (e) {
            errors.push(`-${tag}: ${e instanceof Error ? e.message : String(e)}`);
        }
        await delay(100);
    }

    return { ids: result, errors };
}


